// optimistic append with expectedVersion (simplified)
const streams = {}; // { streamId: {events: [], version: number}}

function appendWithExpectedVersion(streamId, event, expectedVersion) {
  const stream = streams[streamId] || {events: [], version: 0};
  if (stream.version !== expectedVersion) {
    throw new Error('Concurrency error: expected version ' + expectedVersion + ' got ' + stream.version);
  }
  stream.events.push({...event, timestamp: Date.now()});
  stream.version += 1;
  streams[streamId] = stream;
  return stream.version;
}

// replay
function replay(streamId) {
  const stream = streams[streamId] || {events: []};
  return stream.events;
}
